; ラドミラの塔

name = ラドミラの塔16Ｆ
insideName = 16Ｆ
upper = ラドミラの塔17Ｆ
lower = ラドミラの塔15Ｆ
level = 80
bgm = tomb
margin = 3
shadow = dark
sky = dawnforest
roof = stone
effect = screen_dark

; パーツ画像
━ = stone_h
… = half
＋ = stone_h
　 = marble
〼 = marble
毒 = poison
△ = rock
／ = door
☖ = arch
⧻ = fence
┯ = button
⑸ = br_maxhp
⑹ = br_agl

; 敵情報
monsters = レブナント,スケルトンキング,ゴースト,パワーリッチ

; 宝箱
box[1] = 石化解除薬,石化解除薬,運の秘薬,ドクロの杖_ub,死の指輪_ub,死の大斧_ub
box[2] = 罠はない,悪魔の彫像

[map]
